templates.template:
CREATE OR REPLACE FUNCTION NOMBRE_FUNCION (
    P_PARAM1 IN NUMBER,
    P_PARAM2 IN VARCHAR2
)
RETURN NUMBER
IS
    V_RESULTADO NUMBER;
    V_VARIABLE2 VARCHAR2(100);
BEGIN
    RETURN V_RESULTADO;

EXCEPTION
    WHEN OTHERS THEN
        RETURN -1;
END;

CREATE OR REPLACE PACKAGE NOMBRE_PAQUETE
IS
    V_VARIABLE_GLOBAL NUMBER;

    PROCEDURE NOMBRE_PROCEDURE (
        P_PARAM1 IN NUMBER
    );

    FUNCTION NOMBRE_FUNCION (
        P_PARAM1 IN NUMBER
    ) RETURN NUMBER;
END;

CREATE OR REPLACE PROCEDURE NOMBRE_PROCEDURE (
    P_PARAM1 IN NUMBER,
    P_PARAM2 IN VARCHAR2
)
IS
    V_VARIABLE1 NUMBER;
    V_VARIABLE2 VARCHAR2(100);
BEGIN

EXCEPTION
    WHEN OTHERS THEN
        DBMS_OUTPUT.PUT_LINE('ERROR');
END;
